// ============================================================
// MISSED CALL TEXT-BACK SYSTEM (Stromation Template)
// ============================================================
// Deploy per client: swap TWILIO creds, BUSINESS_NAME, OWNER_PHONE/EMAIL
// Twilio triggers this webhook on missed/unanswered calls via a TwiML Bin
// or Twilio Studio flow that checks call status.
//
// SETUP FOR EACH CLIENT:
// 1. Buy Twilio number for client (or use their existing one)
// 2. Set Twilio voice webhook to TwiML that rings their phone
//    with a fallback action URL pointing to this webhook
// 3. Update the 5 config vars below
// ============================================================

// ===== CLIENT CONFIG (change per deployment) =====
const BUSINESS_NAME = 'Acme Pest Control';        // client business name
const OWNER_PHONE = '+19725551234';                // owner cell for SMS alerts
const OWNER_EMAIL = 'owner@example.com';           // owner email for lead alerts
const TWILIO_SID = 'AC_YOUR_ACCOUNT_SID';          // client Twilio account SID
const TWILIO_TOKEN = 'your_auth_token';            // client Twilio auth token
const TWILIO_FROM = '+18555551234';                // Twilio number (the business line)
const OPENAI_KEY = 'sk-proj-YOUR_KEY';             // OpenAI key (use Stromation key or client key)
const BOOKING_LINK = 'https://cal.com/your-link';  // client booking link (Cal.com, Calendly, etc.)
// ===== END CONFIG =====

// Base64 helper (Buffer.from blocked in n8n sandbox)
function b64(str) {
  var chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/';
  var result = '';
  var i = 0;
  while (i < str.length) {
    var a = str.charCodeAt(i++);
    var b = i < str.length ? str.charCodeAt(i++) : 0;
    var c = i < str.length ? str.charCodeAt(i++) : 0;
    var n = (a << 16) | (b << 8) | c;
    result += chars[(n >> 18) & 63] + chars[(n >> 12) & 63];
    result += (i - 2 < str.length) ? chars[(n >> 6) & 63] : '=';
    result += (i - 1 < str.length) ? chars[n & 63] : '=';
  }
  return result;
}

async function sendSMS(to, body) {
  const auth = b64(TWILIO_SID + ':' + TWILIO_TOKEN);
  try {
    const result = await this.helpers.httpRequest({
      url: 'https://api.twilio.com/2010-04-01/Accounts/' + TWILIO_SID + '/Messages.json',
      method: 'POST',
      headers: {
        'Authorization': 'Basic ' + auth,
        'Content-Type': 'application/x-www-form-urlencoded'
      },
      body: 'Body=' + encodeURIComponent(body) + '&To=' + encodeURIComponent(to) + '&From=' + encodeURIComponent(TWILIO_FROM)
    });
    return { success: true, sid: result.sid };
  } catch (err) {
    return { success: false, error: String(err.message || err) };
  }
}

// Extract call data from Twilio webhook
const input = $input.first().json;
const body = input.body || input;
const callerPhone = String(body.From || body.Caller || '').trim();
const callStatus = String(body.CallStatus || body.DialCallStatus || 'no-answer').trim();
const callSid = String(body.CallSid || '').trim();
const calledNumber = String(body.Called || body.To || TWILIO_FROM).trim();
const now = new Date().toISOString();

// Only act on missed/unanswered calls
const missedStatuses = ['no-answer', 'busy', 'failed', 'canceled'];
if (!callerPhone || !missedStatuses.includes(callStatus)) {
  return [{ json: {
    headers: { 'Content-Type': 'text/xml' },
    body: '<?xml version="1.0" encoding="UTF-8"?><Response></Response>',
    _skipped: true,
    _reason: 'Not a missed call or no caller phone: status=' + callStatus
  }}];
}

// Step 1: Send immediate text-back to the caller
const textBackMsg = 'Hey, sorry we missed your call at ' + BUSINESS_NAME + '. How can we help? Reply with what you need and well get you taken care of. You can also book online: ' + BOOKING_LINK;

const smsResult = await sendSMS.call(this, callerPhone, textBackMsg);

// Step 2: Notify business owner immediately
const ownerAlert = 'Missed call from ' + callerPhone + ' at ' + new Date().toLocaleString('en-US', {timeZone: 'America/Chicago'}) + '. Auto-text sent. They may reply soon.';
const ownerSmsResult = await sendSMS.call(this, OWNER_PHONE, ownerAlert);

// Step 3: Return TwiML (empty response since call already ended)
return [{ json: {
  headers: { 'Content-Type': 'text/xml' },
  body: '<?xml version="1.0" encoding="UTF-8"?><Response></Response>',
  callerPhone: callerPhone,
  callStatus: callStatus,
  callSid: callSid,
  textSent: smsResult.success,
  ownerNotified: ownerSmsResult.success,
  timestamp: now,
  _emailSubject: '[' + BUSINESS_NAME + '] Missed Call - ' + callerPhone,
  _emailBody: 'Missed call from ' + callerPhone + '\nTime: ' + now + '\nStatus: ' + callStatus + '\nAuto-text sent: ' + smsResult.success + '\nOwner SMS sent: ' + ownerSmsResult.success
}}];

// ============================================================
// MISSED CALL TEXT-BACK - REPLY HANDLER
// ============================================================
// When the caller texts back, this:
// 1. Uses AI to understand what they need
// 2. Sends a helpful auto-reply
// 3. Logs the lead
// 4. Notifies the business owner with full context
// ============================================================

// ===== CLIENT CONFIG (must match the missed call node) =====
const BUSINESS_NAME = 'Acme Pest Control';
const OWNER_PHONE = '+19725551234';
const OWNER_EMAIL = 'owner@example.com';
const TWILIO_SID = 'AC_YOUR_ACCOUNT_SID';
const TWILIO_TOKEN = 'your_auth_token';
const TWILIO_FROM = '+18555551234';
const OPENAI_KEY = 'sk-proj-YOUR_KEY';
const BOOKING_LINK = 'https://cal.com/your-link';
const BUSINESS_TYPE = 'pest control';  // used for AI context
// ===== END CONFIG =====

function b64(str) {
  var chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/';
  var result = '';
  var i = 0;
  while (i < str.length) {
    var a = str.charCodeAt(i++);
    var b = i < str.length ? str.charCodeAt(i++) : 0;
    var c = i < str.length ? str.charCodeAt(i++) : 0;
    var n = (a << 16) | (b << 8) | c;
    result += chars[(n >> 18) & 63] + chars[(n >> 12) & 63];
    result += (i - 2 < str.length) ? chars[(n >> 6) & 63] : '=';
    result += (i - 1 < str.length) ? chars[n & 63] : '=';
  }
  return result;
}

async function sendSMS(to, body) {
  const auth = b64(TWILIO_SID + ':' + TWILIO_TOKEN);
  try {
    const result = await this.helpers.httpRequest({
      url: 'https://api.twilio.com/2010-04-01/Accounts/' + TWILIO_SID + '/Messages.json',
      method: 'POST',
      headers: {
        'Authorization': 'Basic ' + auth,
        'Content-Type': 'application/x-www-form-urlencoded'
      },
      body: 'Body=' + encodeURIComponent(body) + '&To=' + encodeURIComponent(to) + '&From=' + encodeURIComponent(TWILIO_FROM)
    });
    return { success: true, sid: result.sid };
  } catch (err) {
    return { success: false, error: String(err.message || err) };
  }
}

const input = $input.first().json;
const body = input.body || input;
const fromPhone = String(body.From || '').trim();
const smsBody = String(body.Body || '').trim();
const now = new Date().toISOString();

if (!fromPhone || !smsBody) {
  return [{ json: {
    headers: { 'Content-Type': 'text/xml' },
    body: '<?xml version="1.0" encoding="UTF-8"?><Response></Response>',
    _skipped: true
  }}];
}

// Step 1: AI classifies and extracts info
let leadInfo = { name: null, service_needed: null, address: null, urgency: 'normal' };
try {
  const aiResp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.openai.com/v1/chat/completions',
    headers: { 'Authorization': 'Bearer ' + OPENAI_KEY, 'Content-Type': 'application/json' },
    body: {
      model: 'gpt-4o-mini',
      temperature: 0.1,
      messages: [
        { role: 'system', content: 'You handle SMS replies for ' + BUSINESS_NAME + ', a ' + BUSINESS_TYPE + ' company. Extract info from customer texts. Return JSON only: {"name": "name or null", "service_needed": "what they need in 1 sentence", "address": "address if mentioned or null", "urgency": "emergency/urgent/normal", "reply": "a short friendly reply (under 160 chars) confirming you got their info and someone will reach out soon. mention booking link if appropriate: ' + BOOKING_LINK + '. sound human not corporate."}' },
        { role: 'user', content: smsBody }
      ]
    }
  });
  const parsed = JSON.parse(aiResp.choices[0].message.content);
  leadInfo = { name: parsed.name, service_needed: parsed.service_needed, address: parsed.address, urgency: parsed.urgency || 'normal' };

  // Send AI reply to caller
  const replyText = String(parsed.reply || 'Got it, thanks. Someone from our team will reach out shortly.');
  await sendSMS.call(this, fromPhone, replyText);
} catch(e) {
  // Fallback reply if AI fails
  await sendSMS.call(this, fromPhone, 'Got it, thanks for the info. Someone from ' + BUSINESS_NAME + ' will get back to you shortly.');
  leadInfo.service_needed = smsBody;
}

// Step 2: Notify business owner with full context
const urgencyFlag = leadInfo.urgency === 'emergency' ? 'EMERGENCY ' : leadInfo.urgency === 'urgent' ? 'URGENT ' : '';
const ownerMsg = urgencyFlag + 'New lead from missed call:\n' + fromPhone + '\n' +
  (leadInfo.name ? 'Name: ' + leadInfo.name + '\n' : '') +
  'Need: ' + (leadInfo.service_needed || smsBody) + '\n' +
  (leadInfo.address ? 'Address: ' + leadInfo.address + '\n' : '') +
  'Reply directly to this number to reach them.';

await sendSMS.call(this, OWNER_PHONE, ownerMsg);

// Return TwiML + lead data for email/logging nodes
return [{ json: {
  headers: { 'Content-Type': 'text/xml' },
  body: '<?xml version="1.0" encoding="UTF-8"?><Response></Response>',
  callerPhone: fromPhone,
  message: smsBody,
  leadInfo: leadInfo,
  timestamp: now,
  _emailSubject: '[' + BUSINESS_NAME + '] ' + urgencyFlag + 'Lead: ' + (leadInfo.service_needed || smsBody).substring(0, 50),
  _emailBody: 'New lead from missed call text-back:\n\nPhone: ' + fromPhone + '\n' + (leadInfo.name ? 'Name: ' + leadInfo.name + '\n' : '') + 'Need: ' + (leadInfo.service_needed || smsBody) + '\n' + (leadInfo.address ? 'Address: ' + leadInfo.address + '\n' : '') + 'Urgency: ' + leadInfo.urgency + '\nOriginal message: ' + smsBody
}}];
